import { useEffect, useState } from "react";
import socket from "../socket";

function Player() {
  const [name, setName] = useState("");
  const [joined, setJoined] = useState(false);

  const [question, setQuestion] = useState(null);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState(false); // 🔥 FIX

  // ✅ SOCKET LISTENERS
  useEffect(() => {
    socket.on("connect", () => {
      console.log("Connected:", socket.id);
    });

    socket.on("gameStarted", (q) => {
      setQuestion(q);
      setAnswered(false); // 🔥 reset
    });

    socket.on("nextQuestion", (q) => {
      setQuestion(q);
      setAnswered(false); // 🔥 reset
    });

    socket.on("scoreUpdated", (scores) => {
      if (scores[name] !== undefined) {
        setScore(scores[name]);
      }
    });

    return () => {
      socket.off("connect");
      socket.off("gameStarted");
      socket.off("nextQuestion");
      socket.off("scoreUpdated");
    };
  }, [name]);

  // ✅ JOIN
  const joinGame = () => {
    if (!name) return alert("Enter name");

    socket.emit("joinGame", name);
    setJoined(true);
  };

  // ✅ ANSWER (FIXED)
  const sendAnswer = (option) => {
    if (answered) return; // 🚫 STOP MULTIPLE CLICKS

    const correct = option === question.answer;

    socket.emit("answer", {
      name,
      correct,
    });

    setAnswered(true); // 🔒 lock
  };

  // ❌ BEFORE JOIN
  if (!joined) {
    return (
      <div style={{ padding: "20px" }}>
        <h2>Enter your name</h2>
        <input
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
        <br /><br />
        <button onClick={joinGame}>Join Game</button>
      </div>
    );
  }

  // ✅ AFTER JOIN
  return (
    <div style={{ padding: "20px" }}>
      <h2>Player: {name}</h2>

      {question ? (
        <div>
          <h3>{question.question}</h3>

          {question.options.map((opt, i) => (
            <button
              key={i}
              onClick={() => sendAnswer(opt)}
              style={{ display: "block", margin: "10px" }}
            >
              {opt}
            </button>
          ))}
        </div>
      ) : (
        <p>Waiting for host...</p>
      )}

      <h3>Score: {score}</h3>
    </div>
  );
}

export default Player;
